// ═══════════════════════════════════════════════════
// Owl v2: 情报源配置
// ═══════════════════════════════════════════════════
return {
  targetUrl: 'https://www.theguardian.com/education/universityguide',
  sourceLabel: 'Guardian Education',
  runId: 'owl-v2-' + Date.now()
};

// ═══════════════════════════════════════════════════
// Owl v2: 清洗 + 长度计算
// ═══════════════════════════════════════════════════
const extracted = $input.first().json;
const config = $('📋 情报源配置').first().json;

const title = (extracted.title || '').replace(/<[^>]+>/g, '').trim();
const body = (extracted.body || '').replace(/\s+/g, ' ').trim();
const rawHtml = extracted.rawHtml || '';

return {
  _title: title,
  _body: body,
  _raw_html: rawHtml,
  _content_length: body.length,
  _title_length: title.length,
  _source_url: config.targetUrl,
  _source_label: config.sourceLabel,
  _run_id: config.runId
};

// ═══════════════════════════════════════════════════
// ✅ 抓取成功: 正常输出清洗后的数据
// ═══════════════════════════════════════════════════
const data = $input.first().json;

return {
  _status: 'scrape_success',
  _title: data._title,
  _body: data._body,
  _source_url: data._source_url,
  _source_label: data._source_label,
  _run_id: data._run_id
};

// ═══════════════════════════════════════════════════
// ❌ 主解析失败 → 启用 AI 启发式降级
// 把原始 HTML 喂给 DeepSeek，让它"猜"出内容
// ═══════════════════════════════════════════════════
const data = $input.first().json;

const rawText = (data._raw_html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 8000);

return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0.1,
  max_tokens: 1024,
  messages: [
    {
      role: 'system',
      content: '你是一个网页内容提取器。网页 DOM 解析失败，请从以下杂乱文本中提取核心信息。严格输出 JSON 格式: {"title":"提取的标题","body":"提取的正文摘要(200字内)","success":true/false}。如果实在无法提取有效信息，success 设为 false。'
    },
    {
      role: 'user',
      content: `网页URL: ${data._source_url}\n\n原始文本:\n${rawText}`
    }
  ],
  _source_url: data._source_url,
  _source_label: data._source_label,
  _run_id: data._run_id
};

// ═══════════════════════════════════════════════════
// 解析 AI 降级结果
// ═══════════════════════════════════════════════════
const response = $input.first().json;
const prev = $('🆘 AI 降级: 构建提取 Prompt').first().json;
const raw = response.choices?.[0]?.message?.content || '{}';

let extracted;
try {
  const m = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || [null, raw];
  extracted = JSON.parse(m[1].trim());
} catch {
  extracted = { title: '', body: '', success: false };
}

return {
  _status: extracted.success ? 'ai_fallback_success' : 'ai_fallback_failed',
  _title: extracted.title || '',
  _body: extracted.body || '',
  _source_url: prev._source_url,
  _source_label: prev._source_label,
  _run_id: prev._run_id,
  _ai_raw: raw
};

// ═══════════════════════════════════════════════════
// ✅ AI 提取成功: 输出降级数据
// ═══════════════════════════════════════════════════
const data = $input.first().json;
return {
  _status: 'ai_fallback_recovered',
  _title: data._title,
  _body: data._body,
  _source_url: data._source_url,
  _source_label: data._source_label,
  _run_id: data._run_id,
  _warning: '数据由 AI 降级提取，非直接 DOM 解析'
};

// ═══════════════════════════════════════════════════
// 🚨 双重失败 → 触发报警
// 输出报警数据给 Send Email 节点
// ═══════════════════════════════════════════════════
const data = $input.first().json;

return {
  alert_level: 'CRITICAL',
  alert_type: 'Owl 抓取双重失败',
  source_url: data._source_url,
  source_label: data._source_label,
  failure_reason: 'DOM 解析失败 + AI 降级提取也失败',
  timestamp: new Date().toISOString(),
  run_id: data._run_id,
  // Email 节点需要的字段
  subject: `⚠️ Owl 抓取异常报警 — ${data._source_label}`,
  body: `Owl 情报雷达发生双重熔断故障：\n\n- 目标URL: ${data._source_url}\n- 来源: ${data._source_label}\n- 时间: ${new Date().toISOString()}\n- 原因: DOM 解析失败，AI 启发式降级也未能提取有效内容\n\n建议行动:\n1. 手动访问目标 URL 确认网站是否可访问\n2. 检查目标网站是否改版 (CSS Selector 可能已变更)\n3. 更新 Owl 配置中的 CSS Selector\n4. 如果网站已下线，替换情报源`
};
